// SPDX-License-Identifier: ISC
//! Replay of frozen configuration pipeline vectors generated by a
//! package-main dump test at release-v2.1.5: 76 scenarios drive
//! dcrd's real loadConfig with crafted command lines and config
//! files rooted in temp directories (tokenized as @HOME@), and the
//! full effective configuration — every option field, the cooked
//! values, the network info, and the subsystem log levels — or the
//! error text is compared field for field.  Also pinned: the
//! embedded sample config byte for byte, createDefaultConfigFile
//! under both auth types, and the cleanAndExpandPath battery.

// Index arithmetic over pinned vector rows.
#![allow(clippy::arithmetic_side_effects)]

use std::collections::BTreeMap;
use std::fs;

use dcroxide_node::config::{Assignment, Config, ConfigEnv, sample_dcrd_conf};
use dcroxide_node::logsubsys::SUBSYSTEM_IDS;
use dcroxide_node::{clean_and_expand_path, create_default_config_file, load_config};

const VECTORS: &str = include_str!("data/config_vectors.txt");

fn unhex(s: &str) -> Vec<u8> {
    (0..s.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&s[i..i + 2], 16).unwrap())
        .collect()
}

/// The controlled environment lookups the dump ran under.
fn test_getenv(name: &str) -> Option<String> {
    match name {
        "DCRTESTV1" => Some("/foo/bar".to_string()),
        _ => None,
    }
}

fn test_user_home(name: &str) -> Option<String> {
    match name {
        "" => Some("@UHOME@".to_string()),
        _ => None,
    }
}

/// Replace the generated credential lines like the dump's
/// normalization regexes.
fn normalize_creds(content: &str) -> String {
    let lines: Vec<String> = content
        .split('\n')
        .map(|line| {
            if line.starts_with("rpcuser=") {
                "rpcuser=@RAND@".to_string()
            } else if line.starts_with("rpcpass=") {
                "rpcpass=@RAND@".to_string()
            } else {
                line.to_string()
            }
        })
        .collect();
    lines.join("\n")
}

/// One scenario's parsed input rows.
#[derive(Default)]
struct Scenario {
    name: String,
    args: Vec<String>,
    no_file: bool,
    conf: Vec<String>,
    alt_conf: Vec<String>,
    expect_ok: Option<String>,
    expect_err: Option<String>,
}

/// Rebuild the dump's emitted key=value payload from the effective
/// config.
fn emit_cfg(cfg: &Config, remaining: &[String], home: &str, norm_creds: bool) -> String {
    let rep = |s: &str| s.replace(home, "@HOME@");
    let reps = |v: &[String]| v.iter().map(|s| rep(s)).collect::<Vec<_>>().join(",");
    let dur = dcroxide_node::go_duration_string;
    let mut kv: Vec<String> = Vec::new();
    let mut add = |k: &str, v: String| kv.push(format!("{k}={v}"));

    add("homedir", rep(&cfg.home_dir));
    add("configfile", rep(&cfg.config_file));
    add("datadir", rep(&cfg.data_dir));
    add("logdir", rep(&cfg.log_dir));
    add("logsize", cfg.log_size.clone());
    add("nofilelogging", cfg.no_file_logging.to_string());
    add("dbtype", cfg.db_type.clone());
    add("profile", cfg.profile.clone());
    add("cpuprofile", cfg.cpu_profile.clone());
    add("memprofile", cfg.mem_profile.clone());
    add("testnet", cfg.test_net.to_string());
    add("simnet", cfg.sim_net.to_string());
    add("regnet", cfg.reg_net.to_string());
    add("debuglevel", cfg.debug_level.clone());
    add("sigcachemaxsize", cfg.sig_cache_max_size.to_string());
    add("utxocachemaxsize", cfg.utxo_cache_max_size.to_string());
    add("norpc", cfg.disable_rpc.to_string());
    add("rpclisten", reps(&cfg.rpc_listeners));
    if norm_creds && !cfg.rpc_user.is_empty() {
        add("rpcuser", "@RAND@".to_string());
        add("rpcpass", "@RAND@".to_string());
    } else {
        add("rpcuser", cfg.rpc_user.clone());
        add("rpcpass", cfg.rpc_pass.clone());
    }
    add("authtype", cfg.rpc_auth_type.clone());
    add("clientcafile", rep(&cfg.rpc_client_cas));
    add("rpclimituser", cfg.rpc_limit_user.clone());
    add("rpclimitpass", cfg.rpc_limit_pass.clone());
    add("rpccert", rep(&cfg.rpc_cert));
    add("rpckey", rep(&cfg.rpc_key));
    add("tlscurve", cfg.tls_curve.clone());
    add("altdnsnames", cfg.alt_dns_names.join(","));
    add("notls", cfg.disable_tls.to_string());
    add("rpcmaxclients", cfg.rpc_max_clients.to_string());
    add("rpcmaxwebsockets", cfg.rpc_max_websockets.to_string());
    add(
        "rpcmaxconcurrentreqs",
        cfg.rpc_max_concurrent_reqs.to_string(),
    );
    add("proxy", cfg.proxy.clone());
    add("proxyuser", cfg.proxy_user.clone());
    add("proxypass", cfg.proxy_pass.clone());
    add("onion", cfg.onion_proxy.clone());
    add("onionuser", cfg.onion_proxy_user.clone());
    add("onionpass", cfg.onion_proxy_pass.clone());
    add("noonion", cfg.no_onion.to_string());
    add("torisolation", cfg.tor_isolation.to_string());
    add("addpeer", reps(&cfg.add_peers));
    add("connect", reps(&cfg.connect_peers));
    add("nolisten", cfg.disable_listen.to_string());
    add("listen", reps(&cfg.listeners));
    add("maxsameip", cfg.max_same_ip.to_string());
    add("maxpeers", cfg.max_peers.to_string());
    add("dialtimeout", dur(cfg.dial_timeout_nanos));
    add("peeridletimeout", dur(cfg.peer_idle_timeout_nanos));
    add("noseeders", cfg.disable_seeders.to_string());
    add("nodnsseed", cfg.disable_dns_seed.to_string());
    add("externalip", cfg.external_ips.join(","));
    add("nodiscoverip", cfg.no_discover_ip.to_string());
    add("upnp", cfg.upnp.to_string());
    add("nobanning", cfg.disable_banning.to_string());
    add("banduration", dur(cfg.ban_duration_nanos));
    add("banthreshold", cfg.ban_threshold.to_string());
    add("whitelistraw", cfg.whitelists_raw.join(","));
    add("allowoldforks", cfg.allow_old_forks.to_string());
    add("dumpblockchain", rep(&cfg.dump_blockchain));
    add("assumevalid", cfg.assume_valid.clone());
    add("minrelaytxfee", format!("{}", cfg.min_relay_tx_fee));
    add("limitfreerelay", format!("{}", cfg.free_tx_relay_limit));
    add("norelaypriority", cfg.no_relay_priority.to_string());
    add("maxorphantx", cfg.max_orphan_txs.to_string());
    add("blocksonly", cfg.blocks_only.to_string());
    add("acceptnonstd", cfg.accept_non_std.to_string());
    add("rejectnonstd", cfg.reject_non_std.to_string());
    add("allowoldvotes", cfg.allow_old_votes.to_string());
    add("generate", cfg.generate.to_string());
    add("miningaddrraw", cfg.mining_addrs_raw.join(","));
    add("blockminsize", cfg.block_min_size.to_string());
    add("blockmaxsize", cfg.block_max_size.to_string());
    add("blockprioritysize", cfg.block_priority_size.to_string());
    add("miningtimeoffset", cfg.mining_time_offset.to_string());
    add("nonaggressive", cfg.non_aggressive.to_string());
    add("nominingstatesync", cfg.no_mining_state_sync.to_string());
    add("allowunsyncedmining", cfg.allow_unsynced_mining.to_string());
    add("txindex", cfg.tx_index.to_string());
    add("droptxindex", cfg.drop_tx_index.to_string());
    add("noexistsaddrindex", cfg.no_exists_addr_index.to_string());
    add(
        "dropexistsaddrindex",
        cfg.drop_exists_addr_index.to_string(),
    );
    add("piperx", cfg.pipe_rx.to_string());
    add("pipetx", cfg.pipe_tx.to_string());
    add("lifetimeevents", cfg.lifetime_events.to_string());
    add("boundaddrevents", cfg.bound_addr_events.to_string());

    // Cooked values.
    add("cminfee", cfg.min_relay_tx_fee_atoms.to_string());
    add(
        "cminingaddrs",
        cfg.mining_addrs
            .iter()
            .map(|a| a.to_string())
            .collect::<Vec<_>>()
            .join(","),
    );
    add(
        "cwhitelists",
        cfg.whitelists
            .iter()
            .map(|n| n.to_string())
            .collect::<Vec<_>>()
            .join(","),
    );
    for (key, info) in [
        ("cipv4", &cfg.ipv4_net_info),
        ("cipv6", &cfg.ipv6_net_info),
        ("conion", &cfg.onion_net_info),
    ] {
        add(
            key,
            format!(
                "{};{};{};{};{}",
                info.name,
                info.limited,
                info.reachable,
                info.proxy,
                info.proxy_randomize_credentials
            ),
        );
    }
    add(
        "cnet",
        format!("{};{}", cfg.params.params.name, cfg.params.rpc_port),
    );
    add("remaining", remaining.join(","));
    add(
        "levels",
        SUBSYSTEM_IDS
            .iter()
            .map(|id| format!("{id}={}", cfg.log_levels.0[id]))
            .collect::<Vec<_>>()
            .join(","),
    );

    kv.join("\u{1f}")
}

#[test]
fn config_pipeline_matches_dcrd() {
    let mut localhost: Vec<String> = Vec::new();
    let mut scenarios: BTreeMap<usize, Scenario> = BTreeMap::new();
    let tmp = tempfile::tempdir().unwrap();

    for line in VECTORS.lines() {
        let fields: Vec<&str> = line.splitn(3, '|').collect();
        match fields[0] {
            "clocalhost" => {
                localhost = fields[1].split(',').map(|s| s.to_string()).collect();
            }
            "csample" => {
                assert_eq!(
                    sample_dcrd_conf().as_bytes(),
                    unhex(fields[1]),
                    "sample config"
                );
            }
            "ccreate" => {
                let dest = tmp
                    .path()
                    .join(format!("create-{}.conf", fields[1]))
                    .to_string_lossy()
                    .into_owned();
                create_default_config_file(&dest, fields[1], &|b: &mut [u8]| b.fill(0x42)).unwrap();
                let mut got = fs::read_to_string(&dest).unwrap();
                if fields[1] == "basic" {
                    got = normalize_creds(&got);
                }
                assert_eq!(
                    got.as_bytes(),
                    unhex(fields[2]),
                    "createDefaultConfigFile {}",
                    fields[1]
                );
            }
            "cpath" => {
                let got = clean_and_expand_path(fields[1], &test_getenv, &test_user_home);
                assert_eq!(got, fields[2], "cleanAndExpandPath {}", fields[1]);
            }
            "cscen" => {
                let n: usize = fields[1].parse().unwrap();
                scenarios.entry(n).or_default().name = fields[2].to_string();
            }
            "carg" => {
                let n: usize = fields[1].parse().unwrap();
                scenarios
                    .entry(n)
                    .or_default()
                    .args
                    .push(fields[2].to_string());
            }
            "cnofile" => {
                let n: usize = fields[1].parse().unwrap();
                scenarios.entry(n).or_default().no_file = true;
            }
            "cfile" => {
                let n: usize = fields[1].parse().unwrap();
                scenarios
                    .entry(n)
                    .or_default()
                    .conf
                    .push(fields[2].to_string());
            }
            "califile" => {
                let n: usize = fields[1].parse().unwrap();
                scenarios
                    .entry(n)
                    .or_default()
                    .alt_conf
                    .push(fields[2].to_string());
            }
            "cok" => {
                let n: usize = fields[1].parse().unwrap();
                scenarios.entry(n).or_default().expect_ok = Some(fields[2].to_string());
            }
            "cerr" => {
                let n: usize = fields[1].parse().unwrap();
                scenarios.entry(n).or_default().expect_err = Some(fields[2].to_string());
            }
            other => panic!("unknown row tag {other}"),
        }
    }
    assert_eq!(scenarios.len(), 76, "unexpected scenario count");

    for (n, sc) in &scenarios {
        // A fresh home directory per scenario, like the dump's
        // t.TempDir.
        let home_dir = tempfile::tempdir().unwrap();
        let home = home_dir.path().to_string_lossy().into_owned();

        if !sc.no_file {
            fs::write(home_dir.path().join("dcrd.conf"), sc.conf.join("\n")).unwrap();
        }
        if !sc.alt_conf.is_empty() {
            fs::write(home_dir.path().join("alt.conf"), sc.alt_conf.join("\n")).unwrap();
        }

        // Split the emitted command line into option assignments and
        // positional arguments (the dump restricts itself to
        // --long=value and bare --long forms).
        let mut cli: Vec<Assignment> = Vec::new();
        let mut positional: Vec<String> = Vec::new();
        for arg in &sc.args {
            let arg = arg.replace("@HOME@", &home);
            match arg.strip_prefix("--") {
                Some(opt) => match opt.split_once('=') {
                    Some((name, value)) => cli.push(Assignment {
                        name: name.to_string(),
                        value: Some(value.to_string()),
                    }),
                    None => cli.push(Assignment {
                        name: opt.to_string(),
                        value: None,
                    }),
                },
                None => positional.push(arg),
            }
        }

        let localhost = localhost.clone();
        let env = ConfigEnv {
            default_home_dir: "/dcroxide-nonexistent-default".to_string(),
            lookup_localhost: Box::new(move || Ok(localhost.clone())),
            interface_by_name: Box::new(|_| None),
            getenv: Box::new(test_getenv),
            user_home: Box::new(test_user_home),
            rand_bytes: Box::new(|b: &mut [u8]| b.fill(0x42)),
        };

        match load_config(&cli, &positional, &env) {
            Ok((cfg, remaining)) => {
                let expected = sc
                    .expect_ok
                    .as_ref()
                    .unwrap_or_else(|| panic!("scenario {n} {}: expected error", sc.name));
                let norm_creds = sc.name == "fresh start creates config";
                let got = emit_cfg(&cfg, &remaining, &home, norm_creds);
                assert_eq!(&got, expected, "scenario {n}: {}", sc.name);
            }
            Err(err) => {
                let expected = sc
                    .expect_err
                    .as_ref()
                    .unwrap_or_else(|| panic!("scenario {n} {}: unexpected error {err}", sc.name));
                let got = err.replace(&home, "@HOME@");
                assert_eq!(&got, expected, "scenario {n}: {}", sc.name);
            }
        }
    }
}
